INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("トゥインクルウィッシュ", 2, 8, 0, "東山奈央", "獣人族", 155, 44, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "ヒヨリ", 16, "人助け、応援", 100101, "A", 27, "人助けが大好き！　前向き格闘娘");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("トゥインクルウィッシュ", 2, 4, 0, "種田梨沙", "ヒューマン", 158, 47, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "ユイ", 17, "料理、人間観察", 100201, "O", 5, "戦闘のサポートが得意な、心優しい少女");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("トゥインクルウィッシュ", 2, 1, 0, "早見沙織", "魔族", 163, 46, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "レイ", 18, "読書、乗馬、お茶", 100301, "B", 12, "クールで何事にも真っ直ぐな剣士");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("リトルリリカル", 5, 8, 0, "諸星すみれ", "ヒューマン", 128, 27, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", "ミソギ", 9, "いたずら、探検", 100401, "O", 10, "探検好きのイタズラっ子");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("王宮騎士団（NIGHTMARE）", 8, 11, 0, "下田麻美", "獣人族", 146, 40, "？？？", "マツリ", 12, "ヒーローごっこ", 100501, "O", 25, "ヒーローに憧れる騎士見習いの少女");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("悪魔偽王国軍（ディアボロス）", 7, 11, 0, "浅倉杏美", "魔族", 150, 42, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", "アカリ", 13, "サックス", 100601, "O", 22, "甘え上手なみんなの人気者");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("悪魔偽王国軍（ディアボロス）", 7, 1, 0, "雨宮天", "魔族", 130, 32, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "ミヤコ", 14, "プリンを食べること", 100701, "B", 23, "プリン大好きゴースト娘");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("ヴァイスフリューゲル　ランドソル支部", 15, 10, 0, "大空直美", "エルフ", 150, 40, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", "ユキ", 14, "鏡で自分を見ること", 100801, "AB", 10, "ボクは誰よりも美しい");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("トワイライトキャラバン", 13, 7, 0, "髙野麻美", "魔族", 159, 45, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", "アンナ", 17, "小説執筆", 100901, "A", 5, "前世を信じる中二病患者、「疾風の冥姫」");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("自警団（カォン）", 10, 9, 0, "内田真礼", "獣人族", 155, 42, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", "マホ", 16, "空想、ぬいぐるみ集め", 101001, "O", 22, "マホマホ王国のプリンセス");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("ラビリンス", 3, 8, 0, "阿澄佳奈", "ヒューマン", 156, 44, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", "リノ", 15, "お裁縫", 101101, "A", 25, "人懐っこくてマシンガントークな妹系少女");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("フォレスティエ", 6, 12, 0, "大橋彩香", "エルフ", 156, 46, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", "ハツネ", 17, "妹と遊ぶこと、二度寝、昼寝、早寝", 101201, "A", 24, "みんなのために超能力を使う眠り姫");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("トワイライトキャラバン", 13, 8, 0, "佳村はるか", "魔族", 166, 55, "", "ナナカ", 18, "読書、魔法", 101301, "O", 21, "オタク全開な魔法少女");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("自警団（カォン）", 10, 11, 0, "水瀬いのり", "獣人族", 152, 41, "test", "カスミ", 15, "読書、推理", 101401, "AB", 3, "頭脳明晰な美少女名探偵");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("フォレスティエ", 6, 9, 0, "國府田マリ子", "エルフ", 165, 54, "test", "ミサト", 21, "絵本作り", 101501, "O", 5, "母性溢れる優しいみんなの「ミサト先生」");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("ルーセント学院", 14, 4, 0, "上坂すみれ", "魔族", 167, 48, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", "スズナ", 17, "ファッション", 101601, "O", 10, "天真爛漫で人気者のカリスマモデル");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("自警団（カォン）", 10, 7, 0, "高森奈津美", "獣人族", 158, 53, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", "カオリ", 17, "踊り、空手", 101701, "A", 7, "いつでも「なんくるないさ～」な天然娘");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("ルーセント学院", 14, 8, 0, "伊藤静", "魔族", 162, 52, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", "イオ", 23, "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", 101801, "B", 14, "多くの男性を魅了する無垢な女教師");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("リトルリリカル", 5, 4, 0, "日高里菜", "獣人族", 117, 21, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", "ミミ", 10, "かわいいもの集め", 102001, "O", 3, "お歌もにんじんも、ウサギさんも大好き♪");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("サレンディア救護院", 9, 6, 0, "植田佳奈", "ヒューマン", 150, 40, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "クルミ", 12, "観劇、おままごと", 102101, "B", 9, "泣き虫で臆病な守ってあげたい女の子");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("悪魔偽王国軍（ディアボロス）", 7, 11, 0, "原紗友里", "魔族", 150, 40, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", "ヨリ", 13, "ゲーム全般", 102201, "O", 22, "人見知りであまのじゃくな女の子");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("サレンディア救護院", 9, 5, 0, "芹澤優", "ヒューマン", 148, 38, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "アヤネ", 14, "屋内でできる遊び", 102301, "B", 10, "ぷうきちといつも一緒！");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("サレンディア救護院", 9, 12, 0, "悠木碧", "ヒューマン", 154, 43, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", "スズメ", 15, "ご奉仕", 102501, "O", 12, "お嬢さまのためにがんばるドジっ娘メイド");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("牧場（エリザベスパーク）", 11, 1, 0, "小岩井ことり", "獣人族", 144, 42, "test", "リン", 17, "あんパン", 102601, "B", 1, "遊びと睡眠が何より大事なぐうたら娘");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("トワイライトキャラバン", 13, 7, 0, "橋本ちなみ", "魔族", 154, 43, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "エリコ", 16, "実験、裁縫、料理", 102701, "B", 30, "運命の相手に一途すぎる乙女");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("サレンディア救護院", 9, 10, 0, "堀江由衣", "エルフ", 156, 43, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", "サレン", 17, "経営、お茶会", 102801, "A", 4, "救護院を経営する優しい庶民派お嬢様");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("カルミナ", 4, 1, 0, "日笠陽子", "ヒューマン", 157, 40, "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", "ノゾミ", 17, "舞台鑑賞、ダンス", 102901, "B", 24, "歌って踊れる大人気アイドル");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("ヴァイスフリューゲル　ランドソル支部", 15, 8, 0, "佐藤聡美", "ヒューマン", 163, 51, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", "ニノン", 16, "忍法開発", 103001, "O", 31, "トーゴクの神秘、オシエテクダサイ！");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("悪魔偽王国軍（ディアボロス）", 7, 12, 0, "大坪由佳", "魔族", 157, 42, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "シノブ", 18, "占い", 103101, "AB", 22, "占いが得意な霊能少女");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("メルクリウス財団", 12, 3, 0, "松嵜麗", "ヒューマン", 157, 45, "この私とともにいる限り、\nお金に不自由はさせませんわ！", "アキノ", 18, "慈善事業", 103201, "AB", 12, "一人前の商人を目指すパワフルお嬢様");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("牧場（エリザベスパーク）", 11, 3, 0, "新田恵海", "ヒューマン", 142, 35, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", "マヒル", 20, "漫才", 103301, "B", 3, "みんなを笑顔にするお笑い牧場主");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("メルクリウス財団", 12, 3, 0, "今井麻美", "エルフ", 164, 55, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", "ユカリ", 22, "ウインドーショッピング", 103401, "A", 16, "純情でほっとけない大人の女性");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("リトルリリカル", 5, 2, 0, "小倉唯", "エルフ", 118, 21, "test", "キョウカ", 8, "お勉強", 103601, "A", 2, "礼儀正しくしっかり者のちびっ子優等生");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("王宮騎士団（NIGHTMARE）", 8, 8, 0, "茅原実里", "ヒューマン", 149, 43, "test", "トモ", 13, "剣術、年長者をからかう", 103701, "A", 11, "義理堅くてからかい好きな剣術少女");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("牧場（エリザベスパーク）", 11, 11, 0, "小清水亜美", "獣人族", 153, 40, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", "シオリ", 14, "読書、お散歩", 103801, "A", 3, "読書が趣味の病弱少女");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("フォレスティエ", 6, 6, 0, "花澤香菜", "エルフ", 158, 44, "友達ができるその日まで…\nBB団で\nトレーニングですっ！", "アオイ", 13, "友達作りのイメトレ", 104001, "AB", 6, "「友達」に憧れる、エルフの森の女の子");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("カルミナ", 4, 6, 0, "福原綾香", "ヒューマン", 163, 46, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "チカ", 17, "各種楽器", 104201, "O", 3, "人々を守るために歌う、唱喚士の少女");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("自警団（カォン）", 10, 8, 0, "小松未可子", "獣人族", 168, 54, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", "マコト", 17, "お菓子作り", 104301, "O", 9, "男勝りで情に厚いワイルド娘");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("悪魔偽王国軍（ディアボロス）", 7, 5, 0, "丹下桜", "魔族", 172, 50, "test", "イリヤ", "??", "世界征服", 104401, "A", 5, "かつては夜を支配した最強の吸血鬼");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("ヴァイスフリューゲル　ランドソル支部", 15, 11, 0, "長妻樹里", "ヒューマン", 157, 49, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "クウカ", 18, "小説を読むこと", 104501, "AB", 19, "妄想大好き！　ほんとは照れ屋な女の子");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("メルクリウス財団", 12, 3, 0, "沼倉愛美", "獣人族", 158, 48, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "タマキ", 19, "猫とたわむれること", 104601, "AB", 1, "弱きを助け強きをくじく猫娘");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("王宮騎士団（NIGHTMARE）", 8, 10, 0, "川澄綾子", "ヒューマン", 171, 50, "？？？", "ジュン", 25, "格闘技、湯浴み", 104701, "A", 25, "素顔を見せない冷静沈着な女性騎士");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("メルクリウス財団", 12, 11, 0, "田所あずさ", "ヒューマン", 163, 49, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "ミフユ", 20, "傭兵などのアルバイト", 104801, "O", 11, "仕事も私事も効率優先な傭兵少女");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("ラビリンス", 3, 10, 0, "生天目仁美", "ヒューマン", 168, 54, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "シズル", 18, "家事全般", 104901, "O", 24, "お姉ちゃんがお世話してあげるからねっ！");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("ルーセント学院", 14, 1, 0, "久野美咲", "魔族", 120, 22, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", "ミサキ", 11, "ファッション誌鑑賞、コスメ集め", 105001, "A", 3, "ちょっとおませな恋に恋する女の子");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("トワイライトキャラバン", 13, 3, 0, "三石琴乃", "ヒューマン", 166, 53, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", "ミツキ", 27, "研究、実験", 105101, "A", 7, "実験が趣味の危険な科学者");
