INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("ヴァイスフリューゲル　ランドソル支部", 15, 7, 0, "辻あゆみ", "ヒューマン", 140, 33, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", "モニカ", 17, "お菓子屋通い", 105301, "A", 28, "見た目も中身もお子ちゃまな異国の軍人");
