INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("？？？", "", 3, 0, "金元寿子", "ヒューマン", 156, 45, "私ね、一人前の騎空士になりたいんだ\nいつか父さんみたいな騎空士になって、\n空の果てまで旅する。それが私の夢だよ！", "ジータ", 17, "冒険、おしゃべり", 105701, "O", 10, "空への冒険を夢見る騎空士の少女");
