INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("メルクリウス財団", 12, 3, 0, "沼倉愛美", "獣人族", 158, 48, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "タマキ（サマー）", 19, "猫とたわむれること", 107901, "AB", 1, "弱きを助け強きをくじく猫娘");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("メルクリウス財団", 12, 11, 0, "田所あずさ", "ヒューマン", 163, 49, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "ミフユ（サマー）", 20, "傭兵などのアルバイト", 108001, "O", 11, "仕事も私事も効率優先な傭兵少女");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("悪魔偽王国軍（ディアボロス）", 7, 12, 0, "大坪由佳", "魔族", 157, 42, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "シノブ（ハロウィン）", 18, "占い", 108101, "AB", 22, "占いが得意な霊能少女");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("悪魔偽王国軍（ディアボロス）", 7, 1, 0, "雨宮天", "魔族", 130, 32, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "ミヤコ（ハロウィン）", 14, "プリンを食べること", 108201, "B", 23, "プリン大好きゴースト娘");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("ルーセント学院", 14, 1, 0, "久野美咲", "魔族", 120, 22, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", "ミサキ（ハロウィン）", 11, "ファッション誌鑑賞、コスメ集め", 108301, "A", 3, "ちょっとおませな恋に恋する女の子");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("カルミナ", 4, 6, 0, "福原綾香", "ヒューマン", 163, 46, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "チカ（クリスマス）", 17, "各種楽器", 108401, "O", 3, "人々を守るために歌う、唱喚士の少女");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("サレンディア救護院", 9, 6, 0, "植田佳奈", "ヒューマン", 150, 40, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "クルミ（クリスマス）", 12, "観劇、おままごと", 108501, "B", 9, "泣き虫で臆病な守ってあげたい女の子");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("サレンディア救護院", 9, 5, 0, "芹澤優", "ヒューマン", 148, 38, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "アヤネ（クリスマス）", 14, "屋内でできる遊び", 108601, "B", 10, "ぷうきちといつも一緒！");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("トゥインクルウィッシュ", 2, 8, 0, "東山奈央", "獣人族", 155, 44, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "ヒヨリ（ニューイヤー）", 16, "人助け、応援", 108701, "A", 27, "人助けが大好き！　前向き格闘娘");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("トゥインクルウィッシュ", 2, 4, 0, "種田梨沙", "ヒューマン", 158, 47, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "ユイ（ニューイヤー）", 17, "料理、人間観察", 108801, "O", 5, "戦闘のサポートが得意な、心優しい少女");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("トゥインクルウィッシュ", 2, 1, 0, "早見沙織", "魔族", 163, 46, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "レイ（ニューイヤー）", 18, "読書、乗馬、お茶", 108901, "B", 12, "クールで何事にも真っ直ぐな剣士");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("トワイライトキャラバン", 13, 7, 0, "橋本ちなみ", "魔族", 154, 43, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "エリコ（バレンタイン）", 16, "実験、裁縫、料理", 109001, "B", 30, "運命の相手に一途すぎる乙女");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("ラビリンス", 3, 10, 0, "生天目仁美", "ヒューマン", 168, 54, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "シズル（バレンタイン）", 18, "家事全般", 109101, "O", 24, "お姉ちゃんがお世話してあげるからねっ！");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("？？？", "", 12, 0, "日笠陽子", "ヒューマン", 156, 55, "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", "アン", 17, "読書", 109201, "AB", 1, "英霊と契約を結んだマナリアの天才王女");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("？？？", "", 2, 0, "こやまきみこ", "ヒューマン", 144, 45, "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", "ルゥ", 16, "食べること、眠ること", 109301, "O", 4, "マナリア魔法学院の新入生");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("？？？", "", 11, 0, "福原綾香", "半人半竜", 167, 67, "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", "グレア", 17, "ピアノ", 109401, "B", 3, "人を超越した力を有す心優しい竜姫");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("ヴァイスフリューゲル　ランドソル支部", 15, 11, 0, "長妻樹里", "ヒューマン", 157, 49, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "クウカ（オーエド）", 18, "小説を読むこと", 109501, "AB", 19, "妄想大好き！　ほんとは照れ屋な女の子");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("ヴァイスフリューゲル　ランドソル支部", 15, 8, 0, "佐藤聡美", "ヒューマン", 163, 51, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", "ニノン（オーエド）", 16, "忍法開発", 109601, "O", 31, "トーゴクの神秘、オシエテクダサイ！");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("？？？", "", 2, 0, "水瀬いのり", "鬼族", 154, "??", "", "レム", 17, "演劇鑑賞、詩文", 109701, "?", 2, "鬼がかりの万能妹メイド");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("？？？", "", 2, 0, "村川梨衣", "鬼族", 154, "??", "", "ラム", 17, "読書", 109801, "?", 2, "毒舌系鬼姉メイド");
