INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("トゥインクルウィッシュ", 2, 8, 0, "東山奈央", "獣人族", 155, 44, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "ヒヨリ（サマー）", 16, "人助け、応援", 122401, "A", 27, "人助けが大好き！　前向き格闘娘");
