INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("美食殿", 1, 3, 0, "M・A・O", "ヒューマン", 156, 46, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", "ぺコリーヌ（プリンセス）", 17, "食べ歩き、料理", 180401, "O", 31, "いつも元気な腹ペコ少女");
