INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("美食殿", 1, 9, 0, "立花理香", "獣人族", 152, 39, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", "キャル（プリンセス）", 14, "猫と遊ぶ", 180601, "A", 2, "行き倒れの謎のネコミミ魔法使い");
